import { useEffect, useState } from "react";
import { Calendar, Clock, Palette } from "lucide-react";
import { cn } from "@/shadcn/lib/utils";
import { AppearanceSheet } from "@/components/shared/AppearanceSheet";
import { ApiStatus } from "@/components/ui/api-status";
import { SidebarTrigger } from "@/shadcn/components/ui/sidebar";

export default function Header() {
  const [now, setNow] = useState(new Date());
  const [appearanceOpen, setAppearanceOpen] = useState(false);

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const formattedDate = now.toLocaleDateString("en-US", {
    weekday: "short",
    month: "short",
    day: "2-digit",
    year: "numeric",
  });

  const formattedTime = now.toLocaleTimeString("en-US", {
    hour: "numeric",
    minute: "2-digit",
    hour12: true,
  });

  return (
    <>
      <header className="sticky top-0 z-30 flex h-16 items-center justify-between gap-3 border-b border-border bg-card/90 px-4 shadow-sm backdrop-blur-md">

        <SidebarTrigger className="h-9 w-9 rounded-xl bg-primary/10 text-primary hover:bg-primary/20" />

        <div className="flex items-center gap-3">
        <ApiStatus />

        <button
          onClick={() => setAppearanceOpen(true)}
          title="Appearance settings"
          className={cn(
            "flex h-9 w-9 items-center justify-center rounded-xl",
            "bg-primary/10 text-primary transition-colors hover:bg-primary/20",
          )}
        >
          <Palette className="h-4 w-4" strokeWidth={2.5} />
          <span className="sr-only">Appearance settings</span>
        </button>

        {/* Date & Time widget */}
        <div className="flex select-none items-center gap-5 rounded-2xl border border-border bg-card px-3 py-2 shadow-sm ring-1 ring-black/[0.03] transition-all duration-300 hover:shadow-md dark:ring-white/[0.04]">

          <div className="flex items-center gap-3 pl-1">
            <div className="rounded-lg bg-primary/10 p-1.5">
              <Calendar className="h-4 w-4 text-primary" strokeWidth={2.5} />
            </div>
            <span className="mt-0.5 text-[13px] font-bold uppercase tracking-widest text-muted-foreground">
              {formattedDate}
            </span>
          </div>

          <div className="h-6 w-[2px] rounded-full bg-border" />

          <div className="flex items-center gap-3 pr-2">
            <div className="rounded-lg bg-primary/10 p-1.5">
              <Clock className="h-4 w-4 text-primary" strokeWidth={2.5} />
            </div>
            <span className="mt-0.5 min-w-[76px] text-base font-black tabular-nums tracking-tight text-foreground">
              {formattedTime}
            </span>
          </div>

        </div>

        </div>
      </header>

      <AppearanceSheet open={appearanceOpen} onClose={() => setAppearanceOpen(false)} />
    </>
  );
}
